import type { NodePath } from '@babel/traverse';
import * as t from '@babel/types';
import { EDITABLE_ELEMENT, HTML_TAGS } from './constants';
import type { SourceLocatorAttributeFactory, SourceLocatorAttributes, SourceLocatorAttributeInfo, SourceLocatorTagFilter } from './type';

type CreateJsxLocatorAttributesParams = {
  code: string;
  path: NodePath<t.JSXOpeningElement>;
  prefix: string;
  relativePath: string;
  attributes?: SourceLocatorAttributeFactory;
};

type CreateJsxLocatorAttributesResult = {
  attrs: SourceLocatorAttributes;
  info: SourceLocatorAttributeInfo;
};

export const getJSXTagName = (name: t.JSXOpeningElement['name']): string => {
  return t.isJSXIdentifier(name) ? name.name : '';
};

export const getTextContent = (path: NodePath<t.JSXOpeningElement>): string => {
  let text = '';
  let hasDynamicContent = false;

  const { parent } = path;
  if (!t.isJSXElement(parent)) return '';

  parent.children.forEach((child) => {
    if (t.isJSXText(child)) {
      text += child.value;
    } else if (t.isJSXExpressionContainer(child)) {
      hasDynamicContent = true;
    }
  });

  return hasDynamicContent ? '' : text;
};

export const isSvgChild = (path: NodePath<t.JSXOpeningElement>): boolean => {
  if (t.isJSXIdentifier(path.node.name) && path.node.name.name === 'svg') return false;

  let currentPath: NodePath | null = path.parentPath;

  while (currentPath) {
    if (t.isJSXElement(currentPath.node)) {
      const tagName = currentPath.node.openingElement.name;
      if (t.isJSXIdentifier(tagName) && tagName.name.toLowerCase() === 'svg') {
        return true;
      }
    }
    currentPath = currentPath.parentPath;
  }

  return false;
};

export const isFragmentElement = (path: NodePath<t.JSXOpeningElement>): boolean => {
  return (
    (t.isJSXIdentifier(path.node.name) && path.node.name.name === 'Fragment') ||
    (t.isJSXMemberExpression(path.node.name) &&
      t.isJSXIdentifier(path.node.name.object) &&
      path.node.name.object.name === 'React' &&
      t.isJSXIdentifier(path.node.name.property) &&
      path.node.name.property.name === 'Fragment')
  );
};

export const shouldInjectTag = (tagName: string, filterTag?: SourceLocatorTagFilter): boolean => {
  if (!filterTag) {
    if (!tagName) return false;

    // Lowercase non-DOM renderer tags such as react-three/fiber's `mesh` or `group`
    // cannot accept arbitrary data attributes. Keep the default injection scope to
    // DOM host tags, custom elements, and React-style component tags.
    return HTML_TAGS.includes(tagName) || tagName.includes('-') || /^[A-Z]/.test(tagName);
  }

  if (Array.isArray(filterTag)) {
    return filterTag.includes(tagName);
  }

  return filterTag(tagName);
};

export const hasInjectedDataAttributes = (path: NodePath<t.JSXOpeningElement>, prefix: string): boolean => {
  return path.node.attributes.some(
    (attr) =>
      t.isJSXAttribute(attr) &&
      t.isJSXIdentifier(attr.name) &&
      (attr.name.name === `data-${prefix}-path` || attr.name.name === `data-${prefix}-line`)
  );
};

const getObjectPropertyName = (property: t.ObjectProperty): string | null => {
  if (t.isIdentifier(property.key) && !property.computed) {
    return property.key.name;
  }

  if (t.isStringLiteral(property.key)) {
    return property.key.value;
  }

  return null;
};

export const hasInjectedDataSetAttribute = (path: NodePath<t.JSXOpeningElement>, prefix: string): boolean => {
  return path.node.attributes.some((attr) => {
    if (!t.isJSXAttribute(attr) || !t.isJSXIdentifier(attr.name) || attr.name.name !== 'dataSet') {
      return false;
    }

    if (!attr.value || !t.isJSXExpressionContainer(attr.value) || !t.isObjectExpression(attr.value.expression)) {
      return false;
    }

    return attr.value.expression.properties.some((property) => {
      if (!t.isObjectProperty(property)) return false;

      const propertyName = getObjectPropertyName(property);
      return propertyName === `${prefix}Path` || propertyName === `${prefix}Line`;
    });
  });
};

export const resolveActualLine = (code: string, path: NodePath<t.JSXOpeningElement>, line: number): number => {
  const sourceLines = code.split('\n');
  const tagName = getJSXTagName(path.node.name);

  return (
    sourceLines.findIndex((lineText, index) => {
      const trimmedLine = lineText.trim();
      return trimmedLine.includes(`<${tagName}`) && index >= line - 1;
    }) + 1
  );
};

export const getFullJSXOpeningTag = (code: string, path: NodePath<t.JSXOpeningElement>, actualLine: number): string => {
  const startLine = path.node.loc?.start.line;
  const startColumn = path.node.loc?.start.column;
  const endLine = path.node.loc?.end.line;
  const endColumn = path.node.loc?.end.column;

  if (!startLine || !endLine || startColumn === undefined || endColumn === undefined) {
    return code.split('\n')[actualLine - 1] || '';
  }

  const sourceLines = code.split('\n');

  if (startLine === endLine) {
    const sourceLine = sourceLines[startLine - 1] || '';

    let actualStart = startColumn;
    while (actualStart > 0 && /\s/.test(sourceLine[actualStart - 1])) {
      actualStart--;
    }

    let actualEnd = endColumn;
    while (actualEnd < sourceLine.length && /\s/.test(sourceLine[actualEnd])) {
      actualEnd++;
    }

    return sourceLine.substring(actualStart, actualEnd);
  }

  let fullTag = '';
  for (let i = startLine - 1; i <= endLine - 1; i++) {
    const currentLine = sourceLines[i] || '';
    if (i === startLine - 1) {
      let actualStart = startColumn;
      while (actualStart > 0 && /\s/.test(currentLine[actualStart - 1])) {
        actualStart--;
      }
      fullTag += currentLine.substring(actualStart);
    } else if (i === endLine - 1) {
      let actualEnd = endColumn;
      while (actualEnd < currentLine.length && /\s/.test(currentLine[actualEnd])) {
        actualEnd++;
      }
      fullTag += `\n${currentLine.substring(0, actualEnd)}`;
    } else {
      fullTag += `\n${currentLine}`;
    }
  }

  return fullTag;
};

export const buildDefaultDataAttributes = ({
  prefix,
  relativePath,
  line,
  column,
  tagName,
  fullOpeningTag,
  textContent,
}: {
  prefix: string;
  relativePath: string;
  line: number;
  column: number;
  tagName: string;
  fullOpeningTag: string;
  textContent: string;
}): SourceLocatorAttributes => {
  const isTextElement = EDITABLE_ELEMENT.includes(tagName.toLowerCase());

  return {
    [`data-${prefix}-path`]: `${relativePath}`,
    [`data-${prefix}-line`]: `${line}`,
    [`data-${prefix}-start-column`]: `${column}`,
    [`data-${prefix}-tag`]: `${tagName}`,
    [`data-${prefix}-component`]: encodeURIComponent(fullOpeningTag),
    [`data-${prefix}-id`]: `${relativePath}:${line}:${column}`,
    [`data-${prefix}-project`]: 'jsx',
    [`data-${prefix}-text`]: isTextElement ? encodeURIComponent(textContent) : '',
  };
};

export const createJsxLocatorAttributes = ({
  code,
  path,
  prefix,
  relativePath,
  attributes,
}: CreateJsxLocatorAttributesParams): CreateJsxLocatorAttributesResult | null => {
  const line = path.node.loc?.start.line;
  const column = path.node.loc?.start.column;

  if (!line || column === undefined) {
    return null;
  }

  const actualLine = resolveActualLine(code, path, line);
  const resolvedLine = actualLine || line;
  const tagName = getJSXTagName(path.node.name);
  const info = {
    relativePath,
    line: resolvedLine,
    column,
    tag: tagName,
  };

  if (attributes) {
    return {
      attrs: attributes(info),
      info,
    };
  }

  return {
    attrs: buildDefaultDataAttributes({
      prefix,
      relativePath,
      line: resolvedLine,
      column,
      tagName,
      fullOpeningTag: getFullJSXOpeningTag(code, path, resolvedLine),
      textContent: getTextContent(path),
    }),
    info,
  };
};

export const dataAttributeNameToDataSetKey = (name: string): string => {
  const normalizedName = name.startsWith('data-') ? name.slice(5) : name;

  return normalizedName.replace(/-([a-z])/g, (_, char: string) => {
    return char.toUpperCase();
  });
};
